        elif data_type == DataType.JSONL:
            code += '''            const content = fs.readFileSync(filePath, 'utf-8');
            const lines = content.trim().split('\\n');

            for (let lineNum = 0; lineNum < lines.length; lineNum++) {
                const line = lines[lineNum].trim();
                if (!line) continue;

                const idx = lineNum;
