from dataclasses import dataclass, field
from enum import Enum
from pathlib import Path


# ==============================================================================
# Data Models
# ==============================================================================

class DataType(Enum):
    CSV = "csv"
    TSV = "tsv"
    JSONL = "jsonl"
    JSON = "json"


@dataclass
class ColumnTransform:
    """Represents a column transformation."""
    input_column: Optional[str]
    transform_type: str
    params: Dict[str, Any] = field(default_factory=dict)


@dataclass
class FilterPredicate:
    """Represents a filter predicate."""
    condition: str


# ==============================================================================
# Data Loading
# ==============================================================================

def detect_data_format(filepath: str) -> DataType:
    ext = Path(filepath).suffix.lower().lstrip(".")
    if ext == "csv":
        return DataType.CSV
    if ext == "tsv":
        return DataType.TSV
    if ext == "jsonl":
        return DataType.JSONL
    if ext == "json":
        return DataType.JSON
    raise ValueError(f"Unsupported file extension: {ext}")


def load_input_data(filepath: str) -> List[Dict[str, Any]]:
    data_type = detect_data_format(filepath)

    if data_type == DataType.CSV:
        with open(filepath, "r", encoding="utf-8") as f:
            return list(csv.DictReader(f))
    if data_type == DataType.TSV:
        with open(filepath, "r", encoding="utf-8") as f:
            return list(csv.DictReader(f, delimiter="\t"))
    if data_type == DataType.JSONL:
        rows = []
        with open(filepath, "r", encoding="utf-8") as f:
            for line in f:
                line = line.strip()
                if line:
                    rows.append(json.loads(line))
        return rows
    if data_type == DataType.JSON:
        with open(filepath, "r", encoding="utf-8") as f:
            data = json.load(f)
            return data if isinstance(data, list) else [data]
    raise ValueError(f"Unsupported format: {data_type}")


def _infer_value_type(value: str) -> Any:
    if value is None or value == "":
        return None
    lower = value.lower()
    if lower == "true":
        return True
    if lower == "false":
        return False
    try:
        return int(value)
    except ValueError:
        pass
    try:
        return float(value)
    except ValueError:
        pass
    return value


