def _infer_column_transform(
    in_col: str,
    out_col: str,
    input_rows: List[Dict[str, Any]],
    output_rows: List[Dict[str, Any]],
    kept_indices: List[int],
) -> ColumnTransform:
    in_values = [input_rows[i].get(in_col) for i in kept_indices]
